<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Http\Requests\Admin\PermissionRequest; use App\Models\Permission; use App\Services\Admin\ActivityLogger;
class PermissionController extends Controller { public function index(){return view('admin.permissions.index',['permissions'=>Permission::paginate(15)]);} public function create(){return view('admin.permissions.form',['permission'=>new Permission]);} public function store(PermissionRequest $r, ActivityLogger $l){$p=Permission::create(['name'=>$r->name,'guard_name'=>'web']); $l->log('created','Created permission '.$p->name,$p); return redirect()->route('admin.permissions.index');} public function edit(Permission $permission){return view('admin.permissions.form',compact('permission'));} public function update(PermissionRequest $r, Permission $permission, ActivityLogger $l){$permission->update(['name'=>$r->name]); $l->log('updated','Updated permission '.$permission->name,$permission); return redirect()->route('admin.permissions.index');} public function destroy(Permission $permission, ActivityLogger $l){$l->log('deleted','Deleted permission '.$permission->name,$permission); $permission->delete(); return back();} }
